                { type: "normal", text: "<table style=\"width:100%;border-collapse:collapse;font-size:13px\"><thead><tr style=\"background:#f5f0ff\"><th style=\"padding:8px 10px;border:1px solid #c4b5e0;text-align:left;color:#5b21b6;width:34%\"></th><th style=\"padding:8px 10px;border:1px solid #c4b5e0;text-align:center;color:#5b21b6\">Position dorsale</th><th style=\"padding:8px 10px;border:1px solid #c4b5e0;text-align:center;color:#5b21b6\">Position ventrale</th></tr></thead><tbody><tr><td style=\"padding:8px 10px;border:1px solid #c4b5e0;font-weight:700;background:#faf7ff\">MIN ?</td><td style=\"padding:8px 10px;border:1px solid #c4b5e0\">вҶҳ les risques (depuis la campagne de prГ©vention des annГ©es '90, вҶҳ de <strong>80%</strong> des cas de MIN)</td><td style=\"padding:8px 10px;border:1px solid #c4b5e0;color:#dc2626;font-weight:600\">Principal facteur de risque de la MIN</td></tr><tr><td style=\"padding:8px 10px;border:1px solid #c4b5e0;font-weight:700;background:#faf7ff\">PlagiocГ©phalie ?<br><em style=\"font-weight:400;font-size:11px;color:#78716c\">= dГ©formation du crГўne</em></td><td style=\"padding:8px 10px;border:1px solid #c4b5e0\">вҶ— les risques (ex : S. dans transat)</td><td style=\"padding:8px 10px;border:1px solid #c4b5e0\">вҶҳ les risques</td></tr><tr><td style=\"padding:8px 10px;border:1px solid #c4b5e0;font-weight:700;background:#faf7ff\">Bon pour le squelette ?</td><td style=\"padding:8px 10px;border:1px solid #c4b5e0\"><strong>Non</strong> : ne respecte pas la courbe en C de la colonne vertГ©brale</td><td style=\"padding:8px 10px;border:1px solid #c4b5e0\"><strong>Oui</strong> : s'apparente aux conditions de S. in-utГ©ro ou en portage et permet la bonne courbure de la colonne vertГ©brale</td></tr><tr><td style=\"padding:8px 10px;border:1px solid #c4b5e0;font-weight:700;background:#faf7ff\">RГ©flexe de Moro ?</td><td style=\"padding:8px 10px;border:1px solid #c4b5e0\">TrГЁs prГ©sent, incontrГҙlable (donc multiples rГ©veils)</td><td style=\"padding:8px 10px;border:1px solid #c4b5e0\">LimitГ©</td></tr><tr><td style=\"padding:8px 10px;border:1px solid #c4b5e0;font-weight:700;background:#faf7ff\">MotricitГ© et sentiment de sГ©curitГ© ?</td><td style=\"padding:8px 10px;border:1px solid #c4b5e0\"><strong>Non</strong> : ventre exposГ©, impossibilitГ© de ramper</td><td style=\"padding:8px 10px;border:1px solid #c4b5e0\"><strong>Oui</strong> : permet le mouvement autonome, le nichage et l'odeur de ses mains (liquide amniotique)</td></tr><tr><td style=\"padding:8px 10px;border:1px solid #c4b5e0;font-weight:700;background:#faf7ff\">Automassage ?</td><td style=\"padding:8px 10px;border:1px solid #c4b5e0\">Impossible</td><td style=\"padding:8px 10px;border:1px solid #c4b5e0\"><strong>Possible</strong> : facilite la digestion</td></tr><tr><td style=\"padding:8px 10px;border:1px solid #c4b5e0;font-weight:700;background:#faf7ff\">AccГЁs aux mains / pouces pour faciliter les stratГ©gies de S. autonomes ?</td><td style=\"padding:8px 10px;border:1px solid #c4b5e0\">Non</td><td style=\"padding:8px 10px;border:1px solid #c4b5e0\">Oui</td></tr></tbody></table>" }
