                  title: "Arbre dГ©cisionnel de la HAS",
                  blocks: [
                    { type: "normal", _noBorder: true, text: "<div style=\"font-size:15px;font-weight:700;color:#0f172a;margin-bottom:8px\">вҖў D'aprГЁs <u>l'arbre dГ©cisionnel</u> de la <u>Haute AutoritГ© de SantГ© (HAS)</u> :</div><div style=\"display:flex;align-items:center;gap:10px;margin-bottom:12px;flex-wrap:wrap\"><span style=\"color:#64748b;font-size:15px\">рҹ”—</span><a href=\"https://www.has-sante.fr/upload/docs/application/pdf/2024-03/arbre_decisionnel_de_prise_en_charge_du_reflux_gastro-oesophagien_chez_lenfant_de_moins_de_un_an.pdf\" target=\"_blank\" rel=\"noopener\" style=\"color:#64748b;font-size:14px;text-decoration:underline\">www.has-sante.fr</a><button type=\"button\" title=\"Ouvrir dans une fenГӘtre sГ©parГ©e (pour partage d'Г©cran)\" onclick=\"window.open('https://www.has-sante.fr/upload/docs/application/pdf/2024-03/arbre_decisionnel_de_prise_en_charge_du_reflux_gastro-oesophagien_chez_lenfant_de_moins_de_un_an.pdf','has-aplv-window','width=1100,height=800,menubar=no,toolbar=no,location=yes');return false;\" style=\"width:32px;height:32px;border-radius:50%;border:none;background:#2563eb;color:#fff;cursor:pointer;display:inline-flex;align-items:center;justify-content:center;box-shadow:0 2px 6px rgba(37,99,235,0.35);padding:0;flex-shrink:0\"><span style=\"font-size:14px;margin-left:2px\">в–¶</span></button></div><div style=\"position:relative;width:100%;height:460px;border:1.5px solid #cbd5e0;border-radius:8px;overflow:hidden;background:#fff\"><iframe src=\"https://www.has-sante.fr/upload/docs/application/pdf/2024-03/arbre_decisionnel_de_prise_en_charge_du_reflux_gastro-oesophagien_chez_lenfant_de_moins_de_un_an.pdf#toolbar=0&navpanes=0&scrollbar=0&view=FitH\" style=\"width:100%;height:540px;border:none;background:#fff;margin-top:-4px\" title=\"Arbre dГ©cisionnel HAS вҖ” aperГ§u\" loading=\"lazy\"></iframe></div>" }
                  ]
